void findPairs(Node* head, Node* tail, int target) {
    if (head == nullptr) {
        cout << "[]";
        return;
    }

    Node* left = head;
    Node* right = tail;
    bool found = false;

    // Two-pointer search
    while (left && right && left->data < right->data) {
        int sum = left->data + right->data;

        if (sum == target) {
            cout << "[" << left->data << ", " << right->data << "] ";
            found = true;
            left = left->next;
            right = right->prev;
        }
        else if (sum < target)
            left = left->next;
        else
            right = right->prev;
    }

    if (!found)
        cout << "[]";
}

