function findPairs(head, tail, target) {
  if (!head) {
    console.log("[]");
    return;
  }

  let left = head;
  let right = tail;
  let found = false;
  let result = [];

  // Two-pointer approach
  while (left && right && left.data < right.data) {
    const sum = left.data + right.data;

    if (sum === target) {
      result.push(`[${left.data}, ${right.data}]`);
      found = true;
      left = left.next;
      right = right.prev;
    } 
    else if (sum < target) {
      left = left.next;
    } 
